import React from "react"
import { IconChevronDown } from "@tabler/icons-react"
import { Button } from "@/components/ui/button"
import {
    Collapsible,
    CollapsibleContent,
    CollapsibleTrigger,
} from "@/components/ui/collapsible"

export const FilterSection = ({ title, children, defaultOpen = false }: { title: string, children: React.ReactNode, defaultOpen?: boolean }) => {
    const [isOpen, setIsOpen] = React.useState(defaultOpen)
    return (
        <Collapsible open={isOpen} onOpenChange={setIsOpen} className="w-full border-[1.3px] rounded-lg bg-neutral-200/20 dark:bg-neutral-900/60 border-neutral-200 dark:border-neutral-800 px-1">
            <CollapsibleTrigger asChild className={`h-fit ${isOpen ? "" : "pb-2"} px-0`}>
                <Button variant="ghost" className="w-full justify-between items-center px-2! hover:bg-transparent dark:hover:bg-transparent font-medium text-xs text-neutral-500/90 dark:text-neutral-300 uppercase tracking transition-colors">
                    {title}
                    <IconChevronDown className={`w-4 h-4 transition-transform duration-200 dark:text-neutral-500 ${isOpen ? "" : "-rotate-90"}`} />
                </Button>
            </CollapsibleTrigger>
            <CollapsibleContent className="space-y-1 px-0!">
                {children}
            </CollapsibleContent>
        </Collapsible>
    )
}

import { AppSidebar } from "./components/app-sidebar"
import {
    SidebarInset,
    SidebarProvider,
    SidebarTrigger,
} from "@/components/ui/sidebar"


export const DashboardLayout = ({ children }: { children: React.ReactNode }) => {
    return (
        <div className="bg-white dark:bg-neutral-800 p-3 h-svh w-screen overflow-hidden">
            <SidebarProvider
                className="h-full min-h-0! overflow-hidden gap-2"
                style={{ "--sidebar-width": "250px" } as React.CSSProperties}
            >
                <AppSidebar />
                <SidebarInset className="overflow-hidden min-h-0 rounded-xl border-[1.5px] border-neutral-200  bg-neutral-50 dark:bg-neutral-950 dark:border-neutral-800 p-4">
                    <div className="flex items-center gap-2 mb-4 lg:hidden">
                        <SidebarTrigger className="-ml-1" />
                        <div className="h-4 w-px bg-neutral-200" />
                    </div>
                    {children}
                </SidebarInset>
            </SidebarProvider >
        </div >
    )
}

import { DashboardLayout } from './dashboardLayout'
import MeetingsView from './MeetingsView'

export default function MeetingsDashboardDemo() {
    return (
        <DashboardLayout>
            <MeetingsView />
        </DashboardLayout>
    )
}
